use actix_web::{web, HttpResponse};
use sqlx::PgPool;

async fn get_invoice_details(pool: web::Data<PgPool>, id: web::Path<i32>) -> Result<HttpResponse, String> {
    let invoice_id = id.into_inner();
    let conn = pool.get_ref().await;
    let invoice = sqlx::query("SELECT * FROM invoices WHERE id = $1")
        .bind(invoice_id)
        .fetch_one(conn)
        .await
        .map_err(|e| e.to_string())?;
    
    Ok(HttpResponse::Ok().json(invoice))
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    let pool = PgPool::connect("postgres://user:password@localhost/dbname").await?;
    HttpServer::new(move || {
        App::new()
            .app_data(web::Data::new(pool.clone()))
            .service(
                web::resource("/invoices/{id}")
                    .route(web::get().to(get_invoice_details))
            )
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}